VALUES
  ('judicial-57112235-moex-00087', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '竊盜受刑人在監獄中極易形成次文化團體而成群結黨。根據矯正專家John Irwin之看法，下列關 於竊盜受刑人之次文化團體的特色，何者錯誤？', '["對同僚保持警戒，以防被其竊盜", "認為世界欠缺公平，具濃厚反社會傾向", "強調高超的竊盜技術，嚮往迅速地奪取鉅額金錢", "強調必須時常保持冷靜、沉著"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00088', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '受刑人新收講習後，分別進行初步調查分類，其實施方式敘述下列何者錯誤？', '["直接調查：直接晤談受刑人家庭及警察機關，詢問犯罪經過與身體狀況", "間接調查：以問卷向有關機關查詢受刑人之社會背景等相關事項", "心理測驗：採用儀器或問卷調查受刑人人格、智力、性向、能力等事項", "行動觀察：於接收中心詳加觀察記錄受刑人之行狀表現以建立個案資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00089', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄受刑人之性別以男性為大宗，處遇方案也大多是適用於男性，惟由於女性受刑人身心狀態之迥 異，因此女性受刑人之處遇措施須以較獨特的方式執行。下列關於女性受刑人之處遇對策何者錯誤？', '["應澈底實施男女分監之管教", "加強女性受刑人與其子女之關係", "不須特別區分女性受刑人之犯罪類型，將犯不同罪之女性安置在同一監獄即可", "需特別強化女性受刑人之謀生自立能力 20620"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00090', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '為確保少年司法體系更加公平之應注意事項，下列何者錯誤？', '["應限制少年司法體系工作人員之自由裁量權", "身分犯（StatusOffender）應予除罪化", "少年犯之處遇應走向自願服務性質之特色", "少年法庭應科以少年犯不固定之刑期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00091', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關戒護外醫勤務，下列敘述何者正確？', '["收容人外醫，如果有臨時購物需求，可以准其持有少許金錢", "收容人在醫院門診時，如遇有2人以上，應集中戒護", "戒護外醫，就醫醫院及路線可以由現場戒護人員自行變更，以避免被劫囚", "外醫收容人在醫院如廁時，應尊重隱私，可以不用同行進入廁所內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00092', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '學者H.J.Schneider在調查性侵害犯後發現：「倘性侵害犯未受適當的處遇即離開監獄，在5年內， 有約 35%的人將重操舊業」。故對性侵害犯必須採取妥適之矯正處遇，然在實務上面臨到諸多處 遇困境。關於對性侵害犯之處遇困境下列何者錯誤？', '["專業治療人員之數量嚴重不足", "監獄管教人員參與診療工作之成效不彰", "專為性罪犯設計之評估工具需精進", "缺乏性犯罪相關之專業監獄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00093', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '矯正機關精神疾病收容人之矯正處遇措施，下列何者敘述錯誤？', '["積極擴建精神疾病收容人專區，加強引進精神醫療專業資源", "更生保護會及社福機構派員於出監前介入輔導銜接，並設立出監後安置處所", "增設心理師、社工師及職能治療師等組成專業團隊，加強教化輔導工作", "藥品交由精神疾病收容人自主管理，以利其自我控管規律服藥"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00094', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於監獄暴行之相關因素，其中一項為受刑人具有未婚、刑期與在監時間長、頻繁進出矯正機構 等特徵，在監服刑期間較易發生暴行。請問下列何者為前段敘述之因素？', '["監獄擁擠與暴行", "監獄管理與暴行", "個人背景因素與暴行", "情境因素與暴行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00095', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關矯正機關收容人點名制度，下列何者敘述正確？', '["點名時收容人仍可以自由進出場舍浴廁或庫房", "收容人人數眾多，點名耗時費力，可以請視同作業收容人代為點名", "每日除正式點名外，管理人員可以隨機針對場舍收容人予以點名", "病舍舍房是收容人療養處所，可以不用點名，以避免影響其病情"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00096', 'judicial-57112235', 'judicial-57112235-moex-114-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '監獄暴行可以從不同的理論觀點加以解釋。國內學界雖然還沒有建構理論模式，但國外已經發展 出多項的理論模式。下列所述的理論模式，何者不是用以解釋監獄暴行？', '["行政控制理論（AdministrativeControlTheory）", "威嚇模式（DeterrenceModel）", "輸入模式（ImportationModel）", "受刑人平衡理論（InmateBalanceTheory）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "83a7e2e69390", "answer_pdf_sha1": "9529cae49e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
